    23→
    24→const validateSetting = 'validate.enable';
    25→const suggestionSetting = 'suggestionActions.enabled';
    26→
    27→export default class LanguageProvider extends Disposable {
    28→
    29→	constructor(
    30→		private readonly client: TypeScriptServiceClient,
    31→		private readonly description: LanguageDescription,
    32→		private readonly commandManager: CommandManager,
    33→		private readonly telemetryReporter: TelemetryReporter,
    34→		private readonly typingsStatus: TypingsStatus,
    35→		private readonly fileConfigurationManager: FileConfigurationManager,
    36→		private readonly onCompletionAccepted: (item: vscode.CompletionItem) => void,
    37→	) {
    38→		super();
    39→		vscode.workspace.onDidChangeConfiguration(this.configurationChanged, this, this._disposables);
    40→		this.configurationChanged();
    41→
    42→		client.onReady(() => this.registerProviders());
    43→	}
    44→
    45→	private get documentSelector(): DocumentSelector {
    46→		const semantic: vscode.DocumentFilter[] = [];
    47→		const syntax: vscode.DocumentFilter[] = [];
    48→		for (const language of this.description.languageIds) {
    49→			syntax.push({ language });
    50→			for (const scheme of fileSchemes.getSemanticSupportedSchemes()) {
    51→				semantic.push({ language, scheme });
    52→			}
    53→		}
    54→
    55→		return { semantic, syntax };
    56→	}
    57→
    58→	private async registerProviders(): Promise<void> {
    59→		const selector = this.documentSelector;
    60→
    61→		const cachedNavTreeResponse = new CachedResponse();
    62→
    63→		await Promise.all([
    64→			import('./languageFeatures/callHierarchy').then(provider => this._register(provider.register(selector, this.client))),
    65→			import('./languageFeatures/codeLens/implementationsCodeLens').then(provider => this._register(provider.register(selector, this.description, this.client, cachedNavTreeResponse))),
    66→			import('./languageFeatures/codeLens/referencesCodeLens').then(provider => this._register(provider.register(selector, this.description, this.client, cachedNavTreeResponse))),
    67→			import('./languageFeatures/completions').then(provider => this._register(provider.register(selector, this.description, this.client, this.typingsStatus, this.fileConfigurationManager, this.commandManager, this.telemetryReporter, this.onCompletionAccepted))),
    68→			import('./languageFeatures/copyPaste').then(provider => this._register(provider.register(selector, this.description, this.client))),
    69→			import('./languageFeatures/definitions').then(provider => this._register(provider.register(selector, this.client))),
    70→			import('./languageFeatures/directiveCommentCompletions').then(provider => this._register(provider.register(selector, this.client))),
    71→			import('./languageFeatures/documentHighlight').then(provider => this._register(provider.register(selector, this.client))),
    72→			import('./languageFeatures/documentSymbol').then(provider => this._register(provider.register(selector, this.client, cachedNavTreeResponse))),
    73→			import('./languageFeatures/fileReferences').then(provider => this._register(provider.register(this.client, this.commandManager))),
    74→			import('./languageFeatures/fixAll').then(provider => this._register(provider.register(selector, this.client, this.fileConfigurationManager, this.client.diagnosticsManager))),
    75→			import('./languageFeatures/folding').then(provider => this._register(provider.register(selector, this.client))),
    76→			import('./languageFeatures/formatting').then(provider => this._register(provider.register(selector, this.description, this.client, this.fileConfigurationManager))),
    77→			import('./languageFeatures/hover').then(provider => this._register(provider.register(selector, this.client, this.fileConfigurationManager))),
