    85→			import('./languageFeatures/refactor').then(provider => this._register(provider.register(selector, this.client, cachedNavTreeResponse, this.fileConfigurationManager, this.commandManager, this.telemetryReporter))),
    86→			import('./languageFeatures/references').then(provider => this._register(provider.register(selector, this.client))),
    87→			import('./languageFeatures/rename').then(provider => this._register(provider.register(selector, this.description, this.client, this.fileConfigurationManager))),
    88→			import('./languageFeatures/semanticTokens').then(provider => this._register(provider.register(selector, this.client))),
    89→			import('./languageFeatures/signatureHelp').then(provider => this._register(provider.register(selector, this.client))),
    90→			import('./languageFeatures/smartSelect').then(provider => this._register(provider.register(selector, this.client))),
